          lineGrad.addColorStop(0, 'rgba(' + baseColor + ',0)');
          lineGrad.addColorStop(0.5, 'rgba(' + baseColor + ',' + lineAlpha.toFixed(3) + ')');
          lineGrad.addColorStop(1, 'rgba(' + baseColor + ',0)');
