  var lookaheadStrength = 60 + g.stage * 10;

  var targetLookaheadX = 0;
  var targetLookaheadY = 0;
  if (velMag > 0.1) {
    targetLookaheadX = (g.vx / Math.max(velMag, 0.001)) * lookaheadStrength;
    targetLookaheadY = (g.vy / Math.max(velMag, 0.001)) * lookaheadStrength;
  }

  // Smooth lookahead
  cam._lookaheadX = g.lerp(cam._lookaheadX, targetLookaheadX, lerpT * 0.5);
  cam._lookaheadY = g.lerp(cam._lookaheadY, targetLookaheadY, lerpT * 0.5);

  // Set camera target to player + lookahead
