})

registerModule('Pixel Trail Effect on Mouse Movement', function(g) {
  g._mouseTrail = g._mouseTrail || {
    particles: [],
    lastX: -1,
    lastY: -1,
    pool: [],
    poolIdx: 0
  };

  var s = g._mouseTrail;
  var ctx = g.ctx;
  var LIFETIME = 0.5;
  var MAX_PARTICLES = 120;
  var MIN_DIST = 4;

  // Pre-fill pool
  if (s.pool.length === 0) {
    for (var i = 0; i < MAX_PARTICLES; i++) {
      s.pool.push({
        x: 0, y: 0,
        life: 0, maxLife: LIFETIME,
        size: 2,
        r: 255, gr: 255, b: 255,
        vx: 0, vy: 0,
        active: false
      });
    }
  }

  // Track mouse position via input manager or fallback to canvas event
  if (!s._mouseListening) {
    s._mouseListening = true;
    s.mouseX = g.W / 2;
    s.mouseY = g.H / 2;
    s._onMove = function(e) {
      var rect = g.canvas.getBoundingClientRect();
      s.mouseX = (e.clientX - rect.left) * (g.canvas.width / rect.width);
      s.mouseY = (e.clientY - rect.top) * (g.canvas.height / rect.height);
    };
    g.canvas.addEventListener('mousemove', s._onMove);
  }

  var dt = (g._dt !== undefined) ? g._dt : (1 / 60);
  var mx = s.mouseX !== undefined ? s.mouseX : g.W / 2;
  var my = s.mouseY !== undefined ? s.mouseY : g.H / 2;

  // Palette colors for trail variety
  var palette = [
    [255, 255, 255],
    [0, 255, 170],   // #00ffaa - player color
    [255, 80, 200],
    [80, 200, 255],
    [255, 220, 60]
  ];

  // Acquire from pool
  function acquire() {
    var count = s.pool.length;
    for (var k = 0; k < count; k++) {
      s.poolIdx = (s.poolIdx + 1) % count;
      if (!s.pool[s.poolIdx].active) {
        return s.pool[s.poolIdx];
      }
    }
    // Force-reclaim oldest (smallest life)
    var oldest = s.pool[0];
    for (var m = 1; m < count; m++) {
      if (s.pool[m].life < oldest.life) oldest = s.pool[m];
    }
    return oldest;
  }

  // Spawn particles along mouse path
  var dx = mx - s.lastX;
  var dy = my - s.lastY;
  var moveDist = Math.sqrt(dx * dx + dy * dy);

  if (s.lastX >= 0 && moveDist > MIN_DIST) {
    var steps = Math.min(Math.floor(moveDist / MIN_DIST), 8);
    for (var step = 0; step <= steps; step++) {
      var t = steps > 0 ? step / steps : 0;
      var spawnX = s.lastX + dx * t;
      var spawnY = s.lastY + dy * t;

      var p = acquire();
      var col = palette[Math.floor(g.rand(0, palette.length))];
      var speed = g.rand(0.1, 0.6);
      var angle = Math.atan2(dy, dx) + g.rand(-0.8, 0.8);

      p.active = true;
      p.x = spawnX + g.rand(-1.5, 1.5);
      p.y = spawnY + g.rand(-1.5, 1.5);
      p.life = LIFETIME * g.rand(0.6, 1.0);
      p.maxLife = p.life;
      p.size = g.rand(1.5, 3.5);
      p.r = col[0];
      p.gr = col[1];
      p.b = col[2];
      p.vx = Math.cos(angle) * speed;
      p.vy = Math.sin(angle) * speed - g.rand(0, 0.3);
    }

    s.lastX = mx;
    s.lastY = my;
  } else if (s.lastX < 0) {
    s.lastX = mx;
    s.lastY = my;
  }

  // Update and render trail particles
  ctx.save();

  var pool = s.pool;
  var poolLen = pool.length;

  for (var j = 0; j < poolLen; j++) {
    var p = pool[j];
    if (!p.active) continue;

    p.life -= dt;
    if (p.life <= 0) {
      p.active = false;
      continue;
    }

    p.x += p.vx;
    p.y += p.vy;
    p.vy += 0.015; // slight gravity
    p.vx *= 0.97;

    var frac = p.life / p.maxLife;       // 1 -> 0 as dying
    var alpha = frac * frac;             // quadratic fade
    var sz = p.size * (0.4 + frac * 0.6);

    // Pixel-perfect integer snap for 1-bit aesthetic
    var px = Math.round(p.x);
    var py = Math.round(p.y);
    var psz = Math.max(1, Math.round(sz));

    // Core square pixel
    ctx.globalAlpha = alpha * 0.9;
    ctx.globalCompositeOperation = 'screen';
    ctx.fillStyle = 'rgb(' + (p.r|0) + ',' + (p.gr|0) + ',' + (p.b|0) + ')';
    ctx.fillRect(px - (psz >> 1), py - (psz >> 1), psz, psz);

    // Bright center highlight on newer particles
    if (frac > 0.6 && psz >= 2) {
      ctx.globalAlpha = alpha * 0.6;
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(px - 1, py - 1, 1, 1);
    }
  }

  ctx.globalAlpha = 1;
  ctx.globalCompositeOperation = 'source-over';
  ctx.restore();
})

