    ctx.lineWidth = (2 + flashBoost * 3) * activePct;
    ctx.shadowColor = flashBoost > 0 ? '#ffffff' : '#00ccff';
    ctx.shadowBlur = (12 + flashBoost * 20) * activePct;
    ctx.globalAlpha = activePct;
    drawHex(ctx, px, py, radius, sh.angle, sides);
    ctx.stroke();
    ctx.shadowBlur = 0;
    ctx.globalAlpha = 1;

