    ctx.strokeStyle = 'rgba(0,200,255,' + (0.35 + flashBoost * 0.3) + ')';
    ctx.lineWidth = 1 * activePct;
    ctx.globalAlpha = activePct * 0.7;
    drawHex(ctx, px, py, radius * 0.72, -sh.angle * 1.3, sides);
    ctx.stroke();
    ctx.globalAlpha = 1;

    // Hit indicators (small dots at hex vertices showing remaining hits)
    for (var i = 0; i < sh.maxHits; i++) {
      var dotAngle = sh.angle + (TAU / sh.maxHits) * i - Math.PI / 2;
