    if (activePct < 1) {
      ctx.strokeStyle = 'rgba(0,200,255,' + (1 - activePct) * 0.5 + ')';
      ctx.lineWidth = 2;
      drawHex(ctx, px, py, radius * (1.5 - activePct * 0.5), sh.angle, sides);
      ctx.stroke();
    }
  }

  // HUD element: E key prompt or status
  if (!sh.active && !sh.broken) {
    ctx.font = '10px monospace';
    ctx.textAlign = 'center';
    if (sh.cooldown <= 0) {
      ctx.fillStyle = 'rgba(0,220,255,0.55)';
      ctx.fillText('[E] SHIELD', px, py + radius + 22);
    }
  }

  ctx.restore();

  // Helper: draw hexagon path
  function drawHexPath(c, cx, cy, r, ang, n) {
    for (var k = 0; k < n; k++) {
      var a = ang + (TAU / n) * k;
      var hx = cx + Math.cos(a) * r;
      var hy = cy + Math.sin(a) * r;
