  var entityCount = 0;

  // Pre-allocate entity slots
  for (var i = 0; i < MAX_ENTITIES; i++) {
    entities[i] = {
      id: 0,
      type: '',
      x: 0, y: 0,
      vx: 0, vy: 0,
      hp: 1, maxHp: 1,
      radius: 4,
      color: '#ffffff',
      active: false,
      components: {}
    };
  }

  function resetEntity(e, type, props) {
    e.id = _nextId++;
    e.type = type || '';
    e.x = 0; e.y = 0;
    e.vx = 0; e.vy = 0;
    e.hp = 1; e.maxHp = 1;
    e.radius = 4;
    e.color = '#ffffff';
    e.active = true;
    // Clear components object without allocation
    var comps = e.components;
    for (var k in comps) {
      if (comps.hasOwnProperty(k)) delete comps[k];
    }
    // Apply props
    if (props) {
      for (var p in props) {
        if (props.hasOwnProperty(p)) {
          if (p === 'components') {
            var pc = props.components;
            for (var ck in pc) {
              if (pc.hasOwnProperty(ck)) comps[ck] = pc[ck];
            }
          } else {
            e[p] = props[p];
          }
        }
      }
    }
    return e;
  }

  function spawn(type, props) {
    // Look for an inactive slot in pool for this type
    var pool = pools[type];
    if (!pool) {
      pool = [];
      pools[type] = pool;
    }
    // Try to reuse a dead entity from pool
    for (var i = 0; i < pool.length; i++) {
      var slot = pool[i];
      if (!slot.active) {
        return resetEntity(slot, type, props);
      }
    }
    // Find any inactive entity in master array
    for (var j = 0; j < MAX_ENTITIES; j++) {
      var e = entities[j];
      if (!e.active) {
        var old = e.type;
        resetEntity(e, type, props);
        // Remove from old pool if needed
