    var result = [];
    var pool = pools[type];
    if (!pool) return result;
    for (var i = 0; i < pool.length; i++) {
      if (pool[i].active) result.push(pool[i]);
    }
    return result;
  }

  function queryAll() {
    var result = [];
    for (var i = 0; i < MAX_ENTITIES; i++) {
      if (entities[i].active) result.push(entities[i]);
    }
    return result;
  }

