  if (g.entities && g.entities.length > 0) {
    for (var mi = 0; mi < g.entities.length && mi < MAX_ENTITIES; mi++) {
      var ge = g.entities[mi];
      if (!ge) continue;
      var ne = spawn(ge.type || 'legacy', ge);
