    for (var pi = 0; pi < g.particles.length && pi < MAX_ENTITIES; pi++) {
      var gp = g.particles[pi];
      if (!gp) continue;
      var np = spawn('particle', gp);
      if (np) {
        for (var pk in gp) {
          if (gp.hasOwnProperty(pk) && pk !== 'components') {
            np[pk] = gp[pk];
          }
        }
      }
    }
  }

