  g._ecs = {
    entities: entities,
    pools: pools,
    spawn: spawn,
    kill: kill,
    killEntity: killEntity,
    query: query,
    queryAll: queryAll,
    queryWithComponent: queryWithComponent,
    countActive: countActive,
    MAX_ENTITIES: MAX_ENTITIES
