  var ctx = g.ctx;
  var _debugVisible = true;

  // Per-frame: draw ECS debug stats
  if (_debugVisible && g.tick % 60 === 0) {
    // Lightweight per-minute log (no hot loop alloc)
  }

  // Render debug HUD
  ctx.save();
  ctx.font = '10px monospace';
  ctx.fillStyle = 'rgba(0,255,170,0.35)';
  ctx.textAlign = 'left';
  var activeCount = countActive();
  ctx.fillText('ECS: ' + activeCount + '/' + MAX_ENTITIES, 8, g.H - 8);
  ctx.restore();
})

registerModule('Pixel Trail Effect for Mouse Movement', function(g) {
  g._mouseTrail = g._mouseTrail || {
    mx: g.W / 2,
    my: g.H / 2,
    lastMx: g.W / 2,
    lastMy: g.H / 2,
    particles: [],
    pool: [],
    lastSpawn: 0
  };

  var s = g._mouseTrail;
  var ctx = g.ctx;

  // Track mouse position in canvas coordinates
  if (!s._mouseListenerAttached) {
    s._mouseListenerAttached = true;
    s._onMouseMove = function(e) {
      var rect = g.canvas.getBoundingClientRect();
      var scaleX = g.W / rect.width;
      var scaleY = g.H / rect.height;
      s.mx = (e.clientX - rect.left) * scaleX;
      s.my = (e.clientY - rect.top) * scaleY;
    };
    g.canvas.addEventListener('mousemove', s._onMouseMove, { passive: true });
  }

  // Acquire particle from pool
  function acquire() {
    if (s.pool.length > 0) return s.pool.pop();
    return { x: 0, y: 0, life: 0, maxLife: 0, size: 0, r: 0, gg: 0, b: 0, vx: 0, vy: 0 };
  }

  // Color based on score multiplier
  function getTrailColor() {
    var stage = g.stage || 0;
    var t = Math.min(stage / 5, 1);
    // combo multiplier if available
    var combo = (g._combo && g._combo.multiplier) ? g._combo.multiplier : 1;
    var cm = Math.min((combo - 1) / 4, 1);
    var blend = Math.max(t, cm);

    var r, gg, b;
    if (blend < 0.5) {
      // white -> cyan
      var f = blend * 2;
      r = Math.round(255 * (1 - f));
      gg = 255;
      b = Math.round(255 * (1 - f * 0.2));
    } else {
      // cyan -> magenta
      var f2 = (blend - 0.5) * 2;
      r = Math.round(255 * f2);
      gg = Math.round(255 * (1 - f2));
      b = 255;
    }
    return { r: r, g: gg, b: b };
  }

  var dt = (g._dt !== undefined) ? g._dt : (1 / 60);
  var now = g.tick;

  // Spawn trail particles based on mouse movement distance
  var dx = s.mx - s.lastMx;
  var dy = s.my - s.lastMy;
  var moveDist = Math.sqrt(dx * dx + dy * dy);
  var spawnThreshold = 4;

  if (moveDist > spawnThreshold && (now - s.lastSpawn) >= 1) {
    s.lastSpawn = now;
    var col = getTrailColor();
    var count = Math.min(Math.floor(moveDist / 6) + 1, 5);
    for (var i = 0; i < count; i++) {
      var p = acquire();
      var frac = i / count;
      p.x = s.lastMx + dx * frac + (Math.random() - 0.5) * 2;
      p.y = s.lastMy + dy * frac + (Math.random() - 0.5) * 2;
      p.life = 0.5;
      p.maxLife = 0.5;
      p.size = Math.random() * 2.5 + 1;
      p.r = col.r;
      p.gg = col.g;
      p.b = col.b;
      p.vx = (Math.random() - 0.5) * 20;
      p.vy = (Math.random() - 0.5) * 20;
      s.particles.push(p);
    }
  }

  s.lastMx = s.mx;
  s.lastMy = s.my;

  // Update and render particles
  ctx.save();

  // Apply camera transform if available
  var camApplied = false;
  if (g._cam) {
    ctx.translate(g.W / 2, g.H / 2);
    ctx.scale(g._cam.zoom, g._cam.zoom);
    ctx.translate(-g._cam.x, -g._cam.y);
    camApplied = true;
  }

  ctx.globalCompositeOperation = 'screen';

  var i = s.particles.length;
  while (i--) {
    var p = s.particles[i];
    p.life -= dt;

    if (p.life <= 0) {
      s.particles.splice(i, 1);
      s.pool.push(p);
      continue;
    }

    var lifeRatio = p.life / p.maxLife;
    var eased = lifeRatio * lifeRatio;
    var alpha = eased;

    p.x += p.vx * dt;
    p.y += p.vy * dt;
    p.vx *= 0.92;
    p.vy *= 0.92;

    var curSize = p.size * (0.3 + lifeRatio * 0.7);
    var alpha8 = Math.floor(alpha * 255);
    var hexA = alpha8.toString(16);
    if (hexA.length < 2) hexA = '0' + hexA;

    // Draw glowing pixel
    var cx2 = camApplied ? p.x : p.x;
    var cy2 = camApplied ? p.y : p.y;

    // Outer glow
    var glowSize = curSize * 3;
    var grad = ctx.createRadialGradient(cx2, cy2, 0, cx2, cy2, glowSize);
    grad.addColorStop(0, 'rgba(' + p.r + ',' + p.gg + ',' + p.b + ',' + (alpha * 0.8) + ')');
    grad.addColorStop(0.4, 'rgba(' + p.r + ',' + p.gg + ',' + p.b + ',' + (alpha * 0.3) + ')');
    grad.addColorStop(1, 'rgba(' + p.r + ',' + p.gg + ',' + p.b + ',0)');

    ctx.beginPath();
    ctx.arc(cx2, cy2, glowSize, 0, 6.2832);
    ctx.fillStyle = grad;
    ctx.fill();

    // Core pixel
    ctx.fillStyle = 'rgba(' + p.r + ',' + p.gg + ',' + p.b + ',' + alpha + ')';
    ctx.fillRect(
      Math.round(cx2 - curSize * 0.5),
      Math.round(cy2 - curSize * 0.5),
      Math.ceil(curSize),
      Math.ceil(curSize)
    );
  }

  ctx.globalCompositeOperation = 'source-over';
  ctx.restore();

  // Pool size guard
  if (s.pool.length > 200) s.pool.length = 200;
})

