    var cy0 = cellCoord(y - r);
    var cx1 = cellCoord(x + r);
    var cy1 = cellCoord(y + r);

    for (var cx = cx0; cx <= cx1; cx++) {
      for (var cy = cy0; cy <= cy1; cy++) {
