      var gx = parseInt(parts[0]) * CELL_SIZE;
      var gy = parseInt(parts[1]) * CELL_SIZE;
      var count = grid[keys[i]].length;
      ctx.strokeStyle = 'rgba(0,255,170,' + Math.min(0.5, count * 0.05) + ')';
      ctx.strokeRect(gx, gy, CELL_SIZE, CELL_SIZE);
    }

    // Draw player query radius visualization
    ctx.beginPath();
    ctx.arc(g.px, g.py, 128, 0, Math.PI * 2);
    ctx.strokeStyle = 'rgba(0,255,170,0.15)';
    ctx.lineWidth = 1;
    ctx.stroke();

    ctx.restore();

    // Stats HUD
    var ctx2 = g.ctx;
    ctx2.save();
    ctx2.font = '11px monospace';
    ctx2.fillStyle = 'rgba(0,255,170,0.7)';
    var cellCount = Object.keys(spatial.grid).length;
    var entCount = g.entities ? g.entities.length : 0;
    ctx2.fillText('SPATIAL: ' + cellCount + ' cells | ' + entCount + ' entities | cell=' + CELL_SIZE, 12, g.H - 48);
    ctx2.restore();
  }
})

registerModule('Pixel Collision Ripple Wave Effect', function(g) {
  g._rippleWaves = g._rippleWaves || { pool: [], active: [] };

  var rw = g._rippleWaves;
  var ctx = g.ctx;

  // Pre-allocate pool
  if (rw.pool.length === 0 && rw.active.length === 0) {
    for (var i = 0; i < 48; i++) {
      rw.pool.push({
        x: 0, y: 0,
        radius: 0,
        maxRadius: 0,
        life: 0,
        maxLife: 0,
        color: '#00ffaa',
        pixelCount: 0,
        pixelSpacing: 0,
        intensity: 1
      });
    }
  }

  function spawnRipple(x, y, color, intensity) {
    var wave = rw.pool.length > 0 ? rw.pool.pop() : null;
    if (!wave) return;
    wave.x = x;
    wave.y = y;
    wave.radius = 2;
    wave.maxRadius = 40 + intensity * 30;
    wave.life = 1.0;
    wave.maxLife = 18 + Math.floor(intensity * 12); // frames (0.3-0.5s at 60fps)
    wave.color = color || '#00ffaa';
    wave.pixelCount = 18 + Math.floor(intensity * 12);
    wave.pixelSpacing = 4;
    wave.intensity = intensity || 1;
    rw.active.push(wave);
  }

  // Expose spawn function for other modules
  g._spawnRipple = spawnRipple;

  // Parse hex color to RGB components
  function hexToRgb(hex) {
    hex = hex.replace('#', '');
    if (hex.length === 3) hex = hex[0]+hex[0]+hex[1]+hex[1]+hex[2]+hex[2];
    var n = parseInt(hex, 16);
    return [(n >> 16) & 255, (n >> 8) & 255, n & 255];
  }

  // Collision detection against entities
  var _lastAbsorbed = 0;
  var _lastParticleLen = 0;

  function checkCollisions() {
    // Detect new absorptions via g.absorbed count change
    if (g.absorbed > _lastAbsorbed) {
      var diff = g.absorbed - _lastAbsorbed;
      for (var k = 0; k < diff; k++) {
        var intensity = Math.min(1 + g.stage * 0.15, 2.0);
        var palette = g._palette;
        var col = (palette && palette.accent) ? palette.accent : '#00ffaa';
        spawnRipple(g.px, g.py, col, intensity);
      }
      _lastAbsorbed = g.absorbed;
    }

    // Also check shared entities for proximity hits
    if (g.entities && g.entities.length !== _lastParticleLen) {
      _lastParticleLen = g.entities.length;
    }

    // Check particles array for absorbed/dead particles near player
    if (g._spatial) {
      var near = g._spatial.nearby(g.px, g.py, 28);
      for (var n = 0; n < near.length; n++) {
        var e = near[n];
        if (e && e._rippleHit) continue;
        if (e && e.dead) {
          e._rippleHit = true;
          var c = e.color || '#ffaa00';
          spawnRipple(e.x || g.px, e.y || g.py, c, 0.8);
        }
      }
    }
  }

  // Easing: ease out cubic
  function easeOut(t) {
    var inv = 1 - t;
    return 1 - inv * inv * inv;
  }

  // Render all active ripple waves
  function renderRipples() {
    if (rw.active.length === 0) return;

    ctx.save();

    // Apply camera transform if available
    if (g._cam) {
      ctx.translate(g.W * 0.5, g.H * 0.5);
      ctx.scale(g._cam.zoom, g._cam.zoom);
      ctx.translate(-g._cam.x, -g._cam.y);
    }

    for (var i = rw.active.length - 1; i >= 0; i--) {
      var w = rw.active[i];

      // Update life
      w.life -= 1 / w.maxLife;

      if (w.life <= 0) {
        rw.active.splice(i, 1);
        w._rippleHit = false;
        rw.pool.push(w);
        continue;
      }

      var progress = 1 - w.life; // 0 = start, 1 = end
      var eased = easeOut(progress);
      var alpha = w.life * w.life; // quadratic fade
      var currentRadius = w.radius + eased * w.maxRadius;

      // Parse color
      var rgb = hexToRgb(w.color);
      var r = rgb[0], gC = rgb[1], b = rgb[2];

      // Draw secondary inner ripple (slightly smaller, brighter core)
      var innerRadius = currentRadius * 0.6;
      var innerAlpha = alpha * 0.5;

      // Pixel-dot ripple ring
      var segments = w.pixelCount;
      var angleStep = (Math.PI * 2) / segments;
      var pixelSize = Math.max(1.5, 3 - eased * 1.5);

      // Outer ring
      ctx.globalCompositeOperation = 'screen';
      for (var j = 0; j < segments; j++) {
        var angle = j * angleStep + progress * 0.3; // slight rotation
        var px = w.x + Math.cos(angle) * currentRadius;
        var py = w.y + Math.sin(angle) * currentRadius;

        // Stagger pixel brightness by index for sparkle effect
        var sparkle = 0.6 + 0.4 * Math.sin(j * 2.7 + g.tick * 0.15);
        var fa = alpha * sparkle;
        if (fa < 0.01) continue;

        ctx.globalAlpha = fa * w.intensity;
        ctx.fillStyle = 'rgb(' + r + ',' + gC + ',' + b + ')';
        ctx.fillRect(px - pixelSize * 0.5, py - pixelSize * 0.5, pixelSize, pixelSize);
      }

      // Inner ring (smaller, more translucent)
      var innerSegments = Math.floor(segments * 0.6);
      var innerAngleStep = (Math.PI * 2) / innerSegments;
      var innerPixelSize = Math.max(1, pixelSize * 0.7);
      for (var jj = 0; jj < innerSegments; jj++) {
        var angle2 = jj * innerAngleStep - progress * 0.2;
        var px2 = w.x + Math.cos(angle2) * innerRadius;
        var py2 = w.y + Math.sin(angle2) * innerRadius;

        var sparkle2 = 0.4 + 0.3 * Math.sin(jj * 3.1 + g.tick * 0.12);
        var fa2 = innerAlpha * sparkle2;
        if (fa2 < 0.01) continue;

        ctx.globalAlpha = fa2 * w.intensity;
        ctx.fillStyle = 'rgb(' + Math.min(255, r + 60) + ',' + Math.min(255, gC + 60) + ',' + Math.min(255, b + 60) + ')';
        ctx.fillRect(px2 - innerPixelSize * 0.5, py2 - innerPixelSize * 0.5, innerPixelSize, innerPixelSize);
      }

      // Center flash on first few frames
      if (progress < 0.15) {
        var flashAlpha = (1 - progress / 0.15) * 0.7 * w.intensity;
        var flashR = 8 + eased * 12;
        ctx.globalAlpha = flashAlpha;
        ctx.globalCompositeOperation = 'screen';
        var grad = ctx.createRadialGradient(w.x, w.y, 0, w.x, w.y, flashR);
        grad.addColorStop(0, 'rgba(' + r + ',' + gC + ',' + b + ',1)');
        grad.addColorStop(1, 'rgba(' + r + ',' + gC + ',' + b + ',0)');
        ctx.fillStyle = grad;
        ctx.beginPath();
        ctx.arc(w.x, w.y, flashR, 0, Math.PI * 2);
        ctx.fill();
      }
    }

    ctx.globalAlpha = 1;
    ctx.globalCompositeOperation = 'source-over';
    ctx.restore();
  }

  // Main update
  checkCollisions();
  renderRipples();
})
